import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart'; import 'package:integration_test/integration_test.dart';  /// E2E tests for Claude recommendations: navigate to home feed, /// verify AI recommendation cards or recommendation UI. Used by CI for critical user flow validation. void main() {   IntegrationTestWidgetsFlutterBinding.ensureInitialized();    group('Claude Recommendation E2E', () {     testWidgets('AI recommendations are displayed', (tester) async {       await tester.pumpAndSettle(const Duration(seconds: 3));        final homeFeed = find.byKey(const Key('home_feed'));       if (homeFeed.evaluate().isNotEmpty) {         await tester.tap(homeFeed);         await tester.pumpAndSettle(const Duration(seconds: 2));       }        final recommendationCard = find.byKey(const Key('recommendation_card_0'));       final aiRecommendation = find.textContaining('Recommended');       expect(         recommendationCard.evaluate().isNotEmpty ||             aiRecommendation.evaluate().isNotEmpty,         isTrue,         reason: 'AI recommendations should be visible in feed',       );     });   }); }
